-- Doc 4: 🤖 Manual de Implementación — MetaFollow Sales Coach
INSERT INTO metatronix_docs (
  title, description, category, visibility,
  file_name, file_type, file_size, file_data, text_content,
  uploaded_by_name, created_at
) VALUES (
  '🤖 Manual de Implementación — MetaFollow Sales Coach',
  'Documento de testing intensivo — acanales@ibanormexico.com',
  'manual', 'all',
  'test-doc-4-manual.txt', 'text/plain',
  1443,
  '',
  'MANUAL DE IMPLEMENTACIÓN
MetaFollow Sales Coach IA — Para el Equipo MetaTronix
Versión 3.0 | Abril 2026
════════════════════════════════════════

¿QUÉ ES MetaFollow?
━━━━━━━━━━━━━━━━━━
MetaFollow es el agente de seguimiento de ventas con IA de MetaTronix.
Analiza el pipeline de cada vendedor cada 5 minutos y genera coaching
personalizado con alertas, consejos y análisis predictivo.

CÓMO ACTIVARLO
━━━━━━━━━━━━━
1. Accede a cualquier página del portal MetaTronix
2. Busca el ícono azul con traje en esquina inferior izquierda
3. Clic para abrir el panel de MetaFollow

CARACTERÍSTICAS PRINCIPALES
━━━━━━━━━━━━━━━━━━━━━━━━━━
✅ Lead Scoring IA (0-100): Calcula automáticamente el score de cada
   deal basado en: etapa, confianza, valor, días inactivos, sentimiento
✅ Alertas críticas: Notifica seguimientos vencidos con urgencia
✅ Coaching proactivo: Tips de ventas específicos al contexto del deal
✅ Análisis de win rate: Compara tu tasa de cierre vs benchmark B2B
✅ Chat IA: Responde preguntas de ventas en tiempo real

MÉTRICAS QUE MONITOREA
━━━━━━━━━━━━━━━━━━━━━
- Leads activos / ganados / perdidos
- Pipeline bruto y forecast ponderado
- Días sin actividad por lead
- Seguimientos vencidos
- Sentimiento de últimas comunicaciones

INTEGRACIÓN CON OTROS MÓDULOS
━━━━━━━━━━━━━━━━━━━━━━━━━━━━
- Pipeline CRM: lee datos en tiempo real
- Chat Interno: envía alertas al canal #Ventas
- Centro de Alertas: registra alertas críticas en campana',
  'Testing Intensivo (acanales)',
  NOW() - INTERVAL '6 hours'
);

